// PDF 텍스트를 구조화된 JSON으로 변환 (개선된 제목 추출)
const items = $input.all();
return items.map(item => {
  const text = item.json.text || '';

  console.log('Structure PDF Data - 받은 데이터:', JSON.stringify(item.json, null, 2));

  let formData = item.json._formData;

  if (!formData) {
    console.log('_formData가 없습니다. 기본값을 사용합니다.');
    formData = {
      파일명: '알 수 없음',
      평가항목: '선택 안됨',
      제출시간: ''
    };
  }

  const 파일명 = $('Form Trigger1').first().json['PDF Upload'].filename || '알 수 없음';
  const 평가항목 = $('Form Trigger1').first().json['평가 항목'] || '선택 안됨';
  const 제출시간 = formData.제출시간 || '';

  console.log('추출된 Form 데이터:', { 파일명, 평가항목, 제출시간 });

  // 중복 단어 제거 함수
  function removeDuplicateWords(text) {
    const words = text.split(/\s+/);
    const result = [];
    let prevWord = '';

    for (const word of words) {
      if (word !== prevWord) {
        result.push(word);
        prevWord = word;
      }
    }

    return result.join(' ');
  }

  // 중복 문장 제거 함수
  function removeDuplicateSentences(text) {
    // 먼저 중복 단어 제거
    text = removeDuplicateWords(text);

    // 단어를 배열로 분리
    const words = text.split(/\s+/);

    // 전체 문자열의 절반 길이까지만 패턴으로 검사 (효율성)
    const maxPatternLength = Math.floor(words.length / 2);

    // 가장 긴 반복 패턴부터 찾기
    for (let patternLength = maxPatternLength; patternLength >= 3; patternLength--) {
      const pattern = words.slice(0, patternLength);
      const patternStr = pattern.join(' ');

      // 패턴이 바로 다음에 반복되는지 확인
      const nextSegment = words.slice(patternLength, patternLength * 2);
      const nextStr = nextSegment.join(' ');

      if (patternStr === nextStr) {
        // 반복 패턴 발견 - 한 번만 남기고 나머지 제거
        const remaining = words.slice(patternLength).join(' ');
        return patternStr + ' ' + remaining;
      }
    }

    return text;
  }

  // 문서 메인 제목 추출 함수 (개선: 날짜까지만 포함)
  function extractMainTitle(text) {
    const firstSectionIndex = text.indexOf('□');

    if (firstSectionIndex === -1) {
      // □가 없는 경우: 처음 몇 줄에서 제목 추출
      const lines = text.split('\n').slice(0, 10).filter(line => line.trim().length > 0);
      if (lines.length > 0) {
        return extractTitleUpToDate(lines);
      }
      return '';
    }

    // □ 이전 텍스트에서 제목 추출
    const titleCandidate = text.slice(0, firstSectionIndex).trim();
    const titleLines = titleCandidate
      .split('\n')
      .map(line => line.trim())
      .filter(line => line.length > 0);

    if (titleLines.length === 0) return '';

    return extractTitleUpToDate(titleLines);
  }

  // 날짜 패턴까지만 제목으로 추출하는 함수
  function extractTitleUpToDate(lines) {
    let titleParts = [];

    // 날짜 패턴: YYYY. M., YYYY년 M월, YYYY-MM-DD 등
    const datePattern = /(\d{4}\.\s*\d{1,2}\.|^\d{4}년\s*\d{1,2}월|\d{4}-\d{2}-\d{2})/;

    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];

      // 특정 키워드가 나오면 제목 종료
      const stopKeywords = ['디지털정책관', '정보시스템담당관', '위원회', '시의회', '임시회', '☎', '전화', 'Tel', '팀장', '담당'];
      const hasStopKeyword = stopKeywords.some(keyword => line.includes(keyword));

      if (hasStopKeyword) {
        console.log(`제목 종료: 중지 키워드 발견 - "${line}"`);
        break;
      }

      // 날짜 패턴 확인
      const dateMatch = line.match(datePattern);

      if (dateMatch) {
        // 날짜가 포함된 라인까지 추가
        titleParts.push(line);
        console.log(`제목 종료: 날짜 패턴 발견 - "${line}"`);
        break;
      }

      // 날짜가 아직 안 나왔으면 계속 추가
      titleParts.push(line);

      // 안전장치: 최대 5줄까지만
      if (i >= 4) {
        console.log('제목 종료: 최대 줄 수 도달');
        break;
      }
    }

    // 제목 조합 및 정리
    const combinedTitle = titleParts.join(' ').trim();
    const cleanedTitle = removeDuplicateSentences(combinedTitle);

    console.log('추출된 제목:', cleanedTitle);
    return cleanedTitle;
  }

  // 대제목(□)으로 섹션 분리
  function extractMainSections(text) {
    const sections = {};
    const mainSectionRegex = /□\s*([^\n]+)/g;
    const matches = [...text.matchAll(mainSectionRegex)];

    for (let i = 0; i < matches.length; i++) {
      const sectionTitle = matches[i][1].trim();
      const startIndex = matches[i].index + matches[i][0].length;
      const endIndex = i < matches.length - 1 ? matches[i + 1].index : text.length;
      const sectionContent = text.slice(startIndex, endIndex).trim();

      sections[sectionTitle] = sectionContent;
    }

    return sections;
  }

  // 소제목(❍ (제목)) 파싱 함수
  function parseSubSections(content) {
    const subSectionRegex = /❍\s*\(\s*([^)]+)\s*\)/g;
    const matches = [...content.matchAll(subSectionRegex)];

    if (matches.length === 0) {
      return content.replace(/^\s*❍\s*/gm, '').trim();
    }

    const result = {};

    for (let i = 0; i < matches.length; i++) {
      const subTitle = matches[i][1].trim();
      const startIndex = matches[i].index + matches[i][0].length;
      const endIndex = i < matches.length - 1 ? matches[i + 1].index : content.length;
      const subContent = content.slice(startIndex, endIndex).trim();

      const cleanContent = subContent
        .replace(/^\s*-\s*/gm, '')
        .replace(/^\s*❍\s*/gm, '')
        .trim();

      result[subTitle] = cleanContent;
    }

    return result;
  }

  const 메인제목 = extractMainTitle(text);
  const mainSections = extractMainSections(text);

  const structuredData = {
    메타데이터: {
      문서제목: 메인제목,
      원본파일명: 파일명,
      평가항목: 평가항목,
      제출시간: 제출시간
    }
  };

  for (const [sectionTitle, sectionContent] of Object.entries(mainSections)) {
    const parsedContent = parseSubSections(sectionContent);
    structuredData[sectionTitle] = parsedContent;
  }

  structuredData['원본텍스트'] = text;

  console.log('최종 구조화 데이터:', JSON.stringify(structuredData.메타데이터, null, 2));

  return {
    json: structuredData
  };
});

// 바이너리 데이터를 'data' 필드로 이동하고 Form 데이터도 함께 전달
const items = $input.all();

return items.map(item => {
  const binaryKeys = Object.keys(item.binary || {});
  const firstBinaryKey = binaryKeys[0];

  const formData = {
    파일명: item.json['PDF Upload']?.filename || '알 수 없음',
    평가항목: item.json['평가 항목'] || '선택 안됨',
    제출시간: item.json.submittedAt || ''
  };

  console.log('Prepare Binary - Form 데이터:', formData);

  if (firstBinaryKey) {
    return {
      json: {
        ...item.json,
        _formData: formData
      },
      binary: {
        data: item.binary[firstBinaryKey]
      }
    };
  }

  return {
    json: {
      ...item.json,
      _formData: formData
    },
    binary: item.binary
  };
});

// AI 검토를 위한 데이터 준비
const items = $input.all();

return items.map(item => {
  const 구조화데이터 = item.json;
  const 평가항목 = 구조화데이터.메타데이터?.평가항목 || '';
  const 원본텍스트 = 구조화데이터.원본텍스트 || '';

  // 메타데이터 제외하고 섹션만 추출
  const 섹션데이터 = { ...구조화데이터 };
  delete 섹션데이터.메타데이터;
  delete 섹션데이터.원본텍스트;

  // 검토 대상 텍스트 구성 (구조화된 섹션 우선, 없으면 원본)
  let 검토대상 = '';

  if (Object.keys(섹션데이터).length > 0) {
    // 구조화된 섹션이 있는 경우
    for (const [섹션명, 내용] of Object.entries(섹션데이터)) {
      검토대상 += `\n\n## ${섹션명}\n`;

      if (typeof 내용 === 'object') {
        for (const [하위제목, 하위내용] of Object.entries(내용)) {
          검토대상 += `\n### ${하위제목}\n${하위내용}\n`;
        }
      } else {
        검토대상 += `${내용}\n`;
      }
    }
  } else {
    // 구조화된 섹션이 없으면 원본 텍스트 사용
    검토대상 = 원본텍스트;
  }

  console.log('=== AI 검토 데이터 준비 ===');
  console.log('평가항목:', 평가항목);
  console.log('검토대상 길이:', 검토대상.length);

  return {
    json: {
      평가항목: 평가항목,
      검토대상: 검토대상.trim(),
      메타데이터: 구조화데이터.메타데이터,
      원본구조화데이터: 구조화데이터
    }
  };
});

// AI Agent 출력을 판정별로 그룹화 + Structure PDF Data 출력도 함께 포함

const items = $input.all();

// ✅ 다른 노드 출력 안전 조회
function safeGetNodeFirstJson(nodeName) {
  try {
    const nodeData = $(nodeName).all();
    if (nodeData && nodeData.length > 0) return nodeData[0].json;
    return null;
  } catch (error) {
    console.log(`노드 "${nodeName}" 출력 조회 실패:`, error.message);
    return null;
  }
}

// ✅ Structure PDF Data 출력(구조화 결과) 가져오기
const structuredPdfData = safeGetNodeFirstJson('Structure PDF Data'); // {메타데이터, ...섹션, 원본텍스트}

function extractJsonCandidate(text) {
  if (!text) return '';
  let s = String(text).trim();
  s = s.replace(/```[a-zA-Z]*\n([\s\S]*?)```/g, '$1').trim();
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first >= 0 && last > first) return s.slice(first, last + 1);
  return '';
}

function softRepair(t) {
  if (!t) return '';
  let s = String(t).trim();
  // 스마트쿼트/유사 따옴표 정리
  s = s.replace(/[“”]/g, '"').replace(/[‘’]/g, "'");
  // trailing comma 제거
  s = s.replace(/,\s*([}\]])/g, '$1');
  return s;
}

function fallback(reason) {
  console.log('JSON 파싱 fallback:', reason);
  return {
    '1단계_케이스_분류': '알 수 없음',
    '2단계_항목별_검토': {}
  };
}

return items.map((item) => {
  const raw = item.json.output;
  const rawText = typeof raw === 'string' ? raw : JSON.stringify(raw);

  const cand = extractJsonCandidate(rawText);
  const repaired = softRepair(cand);

  let parsed;
  try {
    parsed = JSON.parse(repaired);
  } catch (e) {
    parsed = fallback(e.message);
  }

  if (!parsed || typeof parsed !== 'object') {
    parsed = fallback('not an object');
  }

  // 원본 항목별 검토 데이터
  const 원본검토 = parsed['2단계_항목별_검토'] || {};

  // 판정별로 그룹화 (중첩 객체 형식)
  const 그룹화된검토 = {};

  for (const [항목코드, 항목데이터] of Object.entries(원본검토)) {
    if (!항목데이터 || !항목데이터.판정 || !항목데이터.사유) continue;

    const 판정 = 항목데이터.판정;
    const 사유 = 항목데이터.사유;

    if (!그룹화된검토[판정]) 그룹화된검토[판정] = {};
    그룹화된검토[판정][항목코드] = 사유;
  }

  console.log('=== 판정별 그룹화 결과 ===');
  console.log('충족 항목 수:', Object.keys(그룹화된검토['충족'] || {}).length);
  console.log('일부 충족 항목 수:', Object.keys(그룹화된검토['일부 충족'] || {}).length);
  console.log('미흡 항목 수:', Object.keys(그룹화된검토['미흡'] || {}).length);

  // 최종 output 구조
  const 결과 = {
    '1단계_케이스_분류': parsed['1단계_케이스_분류'],
    '2단계_항목별_검토': 그룹화된검토
  };

  return {
    json: {
      ...item.json,

      // ✅ 기존 output은 그룹화 결과로 유지
      output: 결과,

      // ✅ LLM 원문도 유지
      __raw_llm: rawText,

      // ✅ Structure PDF Data 출력도 함께 첨부
      // 필요하면 키 이름 바꿔도 됨 (예: 원본구조화데이터)
      구조화PDF: structuredPdfData
    }
  };
});

