// Prepare Quality Check
// ✅ AI Agent - 통합 처리 출력만 파싱
// ✅ "출력없음" 포함 행 + 전체 empty 행 제거

const items = $input.all();

function cleanSectionText(t) {
  return String(t || '')
    .replace(/^■.*?(\r?\n)/gm, '')
    .replace(/\r/g, '')
    .trim();
}

function isEmpty(v) {
  return v === null || v === undefined || String(v).trim() === '';
}

// output에서 섹션 파싱
function parseAIOutput(output) {
  let 추진배경및목적 = '';
  let 추진내용요약 = '';
  let 기대효과 = '';

  const sections = String(output || '').split('■').filter(s => s.trim());

  for (const section of sections) {
    const trimmed = section.trim();

    if (trimmed.startsWith('추진배경') || trimmed.startsWith('추진배경및목적')) {
      추진배경및목적 = cleanSectionText(
        trimmed.replace(/^추진배경.*?(\r?\n)/, '')
      );
      continue;
    }

    if (
      trimmed.startsWith('추진내용') ||
      trimmed.includes('추진내용 요약') ||
      trimmed.includes('추진내용요약')
    ) {
      추진내용요약 = cleanSectionText(
        trimmed.replace(/^추진내용.*?(\r?\n)/, '')
      );
      continue;
    }

    if (trimmed.startsWith('기대효과')) {
      기대효과 = cleanSectionText(
        trimmed
          .replace(/^기대효과.*?(\r?\n)/, '')
          .replace(/\[.*?\]/g, '')
      );
      continue;
    }
  }

  return { 추진배경및목적, 추진내용요약, 기대효과 };
}

const results = [];

for (const item of items) {
  const output = item.json.output ?? item.json.text ?? '';

  // ❌ output에 '출력없음'이 명시된 경우 스킵
  if (String(output).includes('출력없음')) continue;

  const parsed = parseAIOutput(output);

  // ❌ output + 모든 파싱 결과가 empty면 스킵
  const allEmpty =
    isEmpty(output) &&
    isEmpty(parsed.추진배경및목적) &&
    isEmpty(parsed.추진내용요약) &&
    isEmpty(parsed.기대효과);

  if (allEmpty) continue;

  results.push({
    json: {
      output: String(output || '').trim(),
      AI_추진배경및목적: parsed.추진배경및목적,
      AI_추진내용요약: parsed.추진내용요약,
      AI_기대효과: parsed.기대효과
    }
  });
}

return results;

// Parse Quality Result (FIXED)
// ✅ AI Agent - 품질 검토 output(JSON 문자열)에서 quality_review / prepare_quality_check 제대로 추출
// ✅ prepare_quality_check.ai_output_raw 오염 방지: j.output 사용 금지
// ✅ 파싱 실패해도 workflow 안 터지게 안전 처리

const items = $input.all();

function isObject(v) {
  return v && typeof v === 'object' && !Array.isArray(v);
}

function stripCodeFences(s) {
  return String(s || '')
    .replace(/```(?:json)?\s*/gi, '')
    .replace(/```/g, '')
    .trim();
}

function extractFirstJsonObject(text) {
  const s = String(text || '');
  const start = s.indexOf('{');
  if (start < 0) return '';

  let depth = 0;
  let inString = false;
  let escape = false;

  for (let i = start; i < s.length; i++) {
    const ch = s[i];

    if (inString) {
      if (escape) escape = false;
      else if (ch === '\\') escape = true;
      else if (ch === '"') inString = false;
      continue;
    } else {
      if (ch === '"') {
        inString = true;
        continue;
      }
      if (ch === '{') depth++;
      if (ch === '}') depth--;
      if (depth === 0) return s.slice(start, i + 1);
    }
  }
  return '';
}

function safeJsonParse(maybeJsonText) {
  try {
    return { ok: true, value: JSON.parse(maybeJsonText) };
  } catch (e) {
    return { ok: false, error: e?.message || String(e) };
  }
}

// ✅ 오염 방지: ai_output_raw는 절대 j.output로 만들지 않는다
function buildPrepareQualityCheckFromFlat(j) {
  return {
    ai_output_raw: String(j.__ai_output_raw ?? '').trim(), // ✅ 여기 중요
    AI_추진배경및목적: j.AI_추진배경및목적 ?? '',
    AI_추진내용요약: j.AI_추진내용요약 ?? '',
    AI_기대효과: j.AI_기대효과 ?? '',
  };
}

return items.map((item) => {
  const j = item.json || {};

  // 0) 기본 prepare_quality_check 확보 (있으면 유지, 없으면 flat에서 복원)
  const basePrepareQC = isObject(j.prepare_quality_check)
    ? j.prepare_quality_check
    : buildPrepareQualityCheckFromFlat(j);

  // 1) 이미 quality_review가 객체면 그대로 반환(prepareQC 보강만)
  if (isObject(j.quality_review)) {
    return {
      json: {
        ...j,
        prepare_quality_check: basePrepareQC,
        quality_review: j.quality_review,
        _quality_parsed_from: 'direct',
      },
    };
  }

  // 2) 품질검토 노드 output에서 JSON 파싱 시도
  const raw = j.output ?? j.text ?? j.__raw ?? '';
  const cleaned = stripCodeFences(raw);

  // output 전체가 JSON일 수도 있고, 앞뒤 잡문이 섞여있을 수도 있어 첫 JSON을 뽑음
  let jsonText = cleaned.trim().startsWith('{') ? cleaned.trim() : extractFirstJsonObject(cleaned);

  if (!jsonText) {
    return {
      json: {
        ...j,
        prepare_quality_check: basePrepareQC,
        quality_review: {},
        _quality_parsed_from: 'none',
        _quality_parse_error: 'no_json_found_in_output',
      },
    };
  }

  const parsed = safeJsonParse(jsonText);
  if (!parsed.ok || !isObject(parsed.value)) {
    return {
      json: {
        ...j,
        prepare_quality_check: basePrepareQC,
        quality_review: {},
        _quality_parsed_from: 'failed',
        _quality_parse_error: parsed.error || 'json_parse_failed',
        _quality_raw_snippet: String(jsonText).slice(0, 500),
      },
    };
  }

  const outObj = parsed.value;

  // 3) outObj에서 quality_review(또는 구버전 quality_check) 추출
  let quality = {};
  if (isObject(outObj.quality_review)) quality = outObj.quality_review;
  else if (isObject(outObj.quality_check)) quality = outObj.quality_check;

  // 4) outObj에서 prepare_quality_check 추출(있으면 우선), 없으면 base 유지
  const prepareQC = isObject(outObj.prepare_quality_check)
    ? outObj.prepare_quality_check
    : basePrepareQC;

  // 5) outObj 안에 PrepareQC 관련 필드가 최상위로 풀려있을 수도 있으니 보강
  //    (AI Agent가 "입력 JSON 전체 + quality_review" 형태로 출력한 경우 대비)
  const enrichedPrepareQC = {
    ...prepareQC,
    ai_output_raw: String(prepareQC.ai_output_raw ?? '').trim() || String(j.__ai_output_raw ?? '').trim(), // ✅ 오염 방지 유지
    AI_추진배경및목적: prepareQC.AI_추진배경및목적 ?? outObj.AI_추진배경및목적 ?? j.AI_추진배경및목적 ?? '',
    AI_추진내용요약: prepareQC.AI_추진내용요약 ?? outObj.AI_추진내용요약 ?? j.AI_추진내용요약 ?? '',
    AI_기대효과: prepareQC.AI_기대효과 ?? outObj.AI_기대효과 ?? j.AI_기대효과 ?? '',
  };

  // 6) 최종 반환: 기존 j 유지 + (가능하면) outObj도 덮어씌워서 필드 복원 + quality_review/prepareQC 확정
  return {
    json: {
      ...j,
      ...outObj, // ✅ 품질검토 노드가 입력 JSON을 그대로 출력한 경우 여기서 복원됨
      // prepare_quality_check: enrichedPrepareQC,
      quality_review: quality,
      _quality_parsed_from: 'output_json',
      _quality_output_has_quality_review: isObject(outObj.quality_review),
      _quality_output_has_quality_check: isObject(outObj.quality_check),
      _prepare_qc_from_output: isObject(outObj.prepare_quality_check),
    },
  };
});

// Final Report Assembly - 최종 보고서 데이터 조립 (FIX: 월/일 범위 + 우측 연도 생략 범위 보정)
// ✅ 추진기간이 별도 항목에 없으면 추진내용(원본/AI요약/AI요약텍스트)에서 날짜/월/기간 범위를 추출해 채움
// ✅ "일(DD)" 포함 → YYYY.MM.DD~YYYY.MM.DD
// ✅ 월까지만 → YYYY.MM~YYYY.MM (같은 달이면 YYYY.MM)
// ✅ 추가: 25.11~12 / 25.11.15~12.3 처럼 우측 연도 생략도 자동 보정

const items = $input.all();

function asText(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  try { return JSON.stringify(v); } catch (e) { return String(v); }
}

function pickText(v) {
  return String(asText(v)).trim();
}

function notEmpty(s) {
  const t = String(s || '').trim();
  return t && t !== '(생성되지 않음)' && t !== '(원본 없음)' && t !== '(원본없음)';
}

function getFirstObj(...cands) {
  for (const c of cands) {
    if (c && typeof c === 'object' && !Array.isArray(c)) return c;
  }
  return {};
}

function findByName(list, name) {
  if (!Array.isArray(list)) return null;
  return list.find(x => String(x?.항목명 || '').trim() === name) || null;
}

function firstSectionText(labelItem) {
  if (!labelItem || !Array.isArray(labelItem.찾은섹션) || labelItem.찾은섹션.length === 0) return '';
  const first = labelItem.찾은섹션[0];
  const body = typeof first?.내용 === 'string' ? first.내용 : asText(first?.내용);
  return String(body || '').trim();
}

function collectTextFromSections(labelItem) {
  if (!labelItem || !Array.isArray(labelItem.찾은섹션)) return '';
  return labelItem.찾은섹션.map(s => {
    const body = typeof s?.내용 === 'string' ? s.내용 : asText(s?.내용);
    return String(body || '').trim();
  }).filter(Boolean).join(' ');
}

// ------------------------------------------------------------
// 1) Merge 출력이 여러 item(type/항목명/찾은섹션)으로 쪼개져도 모아서 처리
// ------------------------------------------------------------
function collectMergedPayload(allItems) {
  const collected = {
    원본사용: [],
    AI요약: [],
    AI생성: [],
    원본데이터: null,
    구조화PDF: null,
    quality_review: {},
    AI_추진배경및목적: '',
    AI_추진내용요약: '',
    AI_기대효과: '',
  };

  for (const it of allItems) {
    const j = it.json || {};

    if (Array.isArray(j.원본사용)) collected.원본사용.push(...j.원본사용);
    if (Array.isArray(j.AI요약)) collected.AI요약.push(...j.AI요약);
    if (Array.isArray(j.AI생성)) collected.AI생성.push(...j.AI생성);

    if (j.type && j.항목명) {
      const packed = {
        항목명: j.항목명,
        출처: j.출처 ?? null,
        찾은섹션: Array.isArray(j.찾은섹션) ? j.찾은섹션 : [],
      };
      if (j.type === '원본사용') collected.원본사용.push(packed);
      if (j.type === 'AI요약') collected.AI요약.push(packed);
      if (j.type === 'AI생성') collected.AI생성.push(packed);
    }

    if (!collected.원본데이터 && j.원본데이터) collected.원본데이터 = j.원본데이터;
    if (!collected.원본데이터 && j.구조화PDF) collected.원본데이터 = j.구조화PDF;
    if (!collected.구조화PDF && j.구조화PDF) collected.구조화PDF = j.구조화PDF;

    if (notEmpty(j.AI_추진배경및목적) && !notEmpty(collected.AI_추진배경및목적)) {
      collected.AI_추진배경및목적 = pickText(j.AI_추진배경및목적);
    }
    if (notEmpty(j.AI_추진내용요약) && !notEmpty(collected.AI_추진내용요약)) {
      collected.AI_추진내용요약 = pickText(j.AI_추진내용요약);
    }
    if (notEmpty(j.AI_기대효과) && !notEmpty(collected.AI_기대효과)) {
      collected.AI_기대효과 = pickText(j.AI_기대효과);
    }

    if (j.quality_review && typeof j.quality_review === 'object') {
      collected.quality_review = { ...collected.quality_review, ...j.quality_review };
    }
  }

  function uniqLabel(arr) {
    const m = new Map();
    for (const x of arr) {
      const key = [
        String(x?.항목명 || ''),
        String(x?.출처 || ''),
        String(x?.찾은섹션?.[0]?.제목 || '')
      ].join('|');
      if (!m.has(key)) m.set(key, x);
    }
    return Array.from(m.values());
  }

  collected.원본사용 = uniqLabel(collected.원본사용);
  collected.AI요약 = uniqLabel(collected.AI요약);
  collected.AI생성 = uniqLabel(collected.AI생성);

  return collected;
}

// ------------------------------------------------------------
// 2) 추진기간 추출(월/일 + "우측 연도 생략" 범위 보정)
// ------------------------------------------------------------
function pad2(n) { return String(n).padStart(2, '0'); }
function formatYMD(d) { return `${d.getFullYear()}.${pad2(d.getMonth() + 1)}.${pad2(d.getDate())}`; }
function formatYM(d) { return `${d.getFullYear()}.${pad2(d.getMonth() + 1)}`; }

function normalizeYear(yStr) {
  const t = String(yStr || '').trim();
  const y = Number(t);
  if (!Number.isFinite(y)) return null;
  if (t.length === 2) return 2000 + y; // 25 -> 2025
  if (t.length === 4) return y;
  return null;
}

function daysInMonth(y, m) {
  return new Date(y, m, 0).getDate();
}

function makeDateSafe(y, m, d, clampDay = false) {
  const yy = Number(y), mm = Number(m), dd = Number(d);
  if (!yy || !mm || !dd) return null;
  if (mm < 1 || mm > 12) return null;

  let day = dd;
  const dim = daysInMonth(yy, mm);
  if (day < 1) return null;
  if (day > dim) {
    if (!clampDay) return null;
    day = dim;
  }

  const dt = new Date(yy, mm - 1, day);
  if (dt.getFullYear() !== yy || dt.getMonth() !== (mm - 1) || dt.getDate() !== day) return null;
  return dt;
}

// ranges: { start: Date, end: Date, precision: 'day'|'month' }
function extractDateRanges(text) {
  const s = String(text || '');
  const ranges = [];

  // (A) ✅ 우측 연도 생략 범위: 25.11~12 / 25.11.15~12.3 / 2025.11~2 / 25년11월~12월 등
  //  - left: (YY|YYYY).M(.D)?
  //  - right: M(.D)?   (year omitted)
  //  - rule: rightYear = leftYear (+1 if rightMonth < leftMonth)
  const reRightOmitYear = /(?<!\d)(\d{2}|\d{4})\s*(?:[.\-/]\s*|\s*년\s*)(\d{1,2})\s*(?:[.\-/]\s*|\s*월\s*)?(\d{1,2})?\s*(?:일)?\s*(?:~|∼|\-|–|—|부터)\s*(\d{1,2})(?:\s*(?:[.\-/]\s*|\s*월\s*)\s*(\d{1,2})\s*(?:일)?)?(?:\s*까지)?(?!\d)/g;

  let m;
  while ((m = reRightOmitYear.exec(s)) !== null) {
    const y1 = normalizeYear(m[1]);
    const mo1 = Number(m[2]);
    const d1 = m[3] ? Number(m[3]) : null;

    const mo2 = Number(m[4]);
    const d2 = m[5] ? Number(m[5]) : null;

    if (!y1 || !(mo1 >= 1 && mo1 <= 12) || !(mo2 >= 1 && mo2 <= 12)) continue;

    let y2 = y1;
    if (mo2 < mo1) y2 = y1 + 1; // 연도 롤오버

    const leftPrec = d1 ? 'day' : 'month';
    const rightPrec = d2 ? 'day' : 'month';
    const spanPrec = (leftPrec === 'day' || rightPrec === 'day') ? 'day' : 'month';

    const start = d1
      ? makeDateSafe(y1, mo1, d1, true)
      : makeDateSafe(y1, mo1, 1, false);

    const end = d2
      ? makeDateSafe(y2, mo2, d2, true)
      : makeDateSafe(y2, mo2, daysInMonth(y2, mo2), true);

    if (start && end) ranges.push({ start, end, precision: spanPrec });
  }

  // (1) YYYY.MM.DD / YY.MM.DD 단일
  const reYMD = /(?<!\d)(\d{2}|\d{4})\s*[.\-/]\s*(\d{1,2})\s*[.\-/]\s*(\d{1,2})(?!\d)/g;
  while ((m = reYMD.exec(s)) !== null) {
    const yy = normalizeYear(m[1]);
    const mm = Number(m[2]);
    const dd = Number(m[3]);
    if (!yy) continue;
    const dt = makeDateSafe(yy, mm, dd, true);
    if (dt) ranges.push({ start: dt, end: dt, precision: 'day' });
  }

  // (2) YYYY년 M월 D일 / YY년 M월 D일 단일
  const reYMDK = /(?<!\d)(\d{2}|\d{4})\s*년\s*(\d{1,2})\s*월\s*(\d{1,2})\s*일(?!\d)/g;
  while ((m = reYMDK.exec(s)) !== null) {
    const yy = normalizeYear(m[1]);
    const mm = Number(m[2]);
    const dd = Number(m[3]);
    if (!yy) continue;
    const dt = makeDateSafe(yy, mm, dd, true);
    if (dt) ranges.push({ start: dt, end: dt, precision: 'day' });
  }

  // (3) YYYY.MM / YY.MM (월만)
  const reYMdot = /(?<!\d)(\d{2}|\d{4})\s*[.\-/]\s*(\d{1,2})(?!\s*[.\-/]\s*\d)/g;
  while ((m = reYMdot.exec(s)) !== null) {
    const yy = normalizeYear(m[1]);
    const mm = Number(m[2]);
    if (!yy) continue;
    const start = makeDateSafe(yy, mm, 1, false);
    const end = makeDateSafe(yy, mm, daysInMonth(yy, mm), true);
    if (start && end) ranges.push({ start, end, precision: 'month' });
  }

  // (4) YYYY년 M월 / YY년 M월 (월만)
  const reYMK = /(?<!\d)(\d{2}|\d{4})\s*년\s*(\d{1,2})\s*월(?!\s*\d)/g;
  while ((m = reYMK.exec(s)) !== null) {
    const yy = normalizeYear(m[1]);
    const mm = Number(m[2]);
    if (!yy) continue;
    const start = makeDateSafe(yy, mm, 1, false);
    const end = makeDateSafe(yy, mm, daysInMonth(yy, mm), true);
    if (start && end) ranges.push({ start, end, precision: 'month' });
  }

  // (5) 일반 범위: left~right (둘 다 연도 포함된 경우)
  const reSpan = /(\d{2,4}\s*(?:[.\-/]\s*\d{1,2}(?:\s*[.\-/]\s*\d{1,2})?|\s*년\s*\d{1,2}\s*월(?:\s*\d{1,2}\s*일)?))\s*(?:~|∼|\-|–|—|부터)\s*(\d{2,4}\s*(?:[.\-/]\s*\d{1,2}(?:\s*[.\-/]\s*\d{1,2})?|\s*년\s*\d{1,2}\s*월(?:\s*\d{1,2}\s*일)?))(?:\s*까지)?/g;

  let sm;
  while ((sm = reSpan.exec(s)) !== null) {
    const left = sm[1];
    const right = sm[2];

    const L = extractDateRanges(left);
    const R = extractDateRanges(right);

    if (L.length && R.length) {
      let lMin = L[0].start;
      let lPrec = L[0].precision;
      for (const r of L) {
        if (r.start.getTime() < lMin.getTime()) lMin = r.start;
        if (r.precision === 'day') lPrec = 'day';
      }

      let rMax = R[0].end;
      let rPrec = R[0].precision;
      for (const r of R) {
        if (r.end.getTime() > rMax.getTime()) rMax = r.end;
        if (r.precision === 'day') rPrec = 'day';
      }

      const spanPrec = (lPrec === 'day' || rPrec === 'day') ? 'day' : 'month';
      ranges.push({ start: lMin, end: rMax, precision: spanPrec });
    }
  }

  // 유니크
  const uniq = new Map();
  for (const r of ranges) {
    const key = `${formatYMD(r.start)}~${formatYMD(r.end)}|${r.precision}`;
    if (!uniq.has(key)) uniq.set(key, r);
  }
  return Array.from(uniq.values());
}

function formatRangeFromText(text) {
  const ranges = extractDateRanges(text);
  if (!ranges.length) return '';

  const hasDay = ranges.some(r => r.precision === 'day');

  let minStart = ranges[0].start;
  let maxEnd = ranges[0].end;

  for (const r of ranges) {
    if (r.start.getTime() < minStart.getTime()) minStart = r.start;
    if (r.end.getTime() > maxEnd.getTime()) maxEnd = r.end;
  }

  if (hasDay) {
    return `${formatYMD(minStart)}~${formatYMD(maxEnd)}`;
  }

  const a = formatYM(minStart);
  const b = formatYM(maxEnd);
  return (a === b) ? a : `${a}~${b}`;
}

