// Parse Revised Content - 재작성된 내용 파싱 및 병합 (품질검토 부적합 항목만 교체)
// ✅ 주의: 이 노드는 "AI Agent - 부적합 재작성" 출력(item.json.output)과
//         기존 품질검토 결과(item.json.품질검토결과.부적합항목)를 기반으로
//         item.json.AI생성_* 필드만 필요한 항목에 한해 교체합니다.

const items = $input.all();

function pickText(val) {
  if (val === null || val === undefined) return '';
  return typeof val === 'string' ? val : JSON.stringify(val);
}

// "■ 섹션" 기반 파싱 + 없을 경우에도 최대한 추출(방어)
function parseRewrittenSections(text) {
  const result = {
    추진배경및목적: '',
    추진내용: '',
    기대효과: '',
  };

  const raw = pickText(text).trim();
  if (!raw) return result;

  // 기본: ■ 로 섹션 분리
  const blocks = raw.split('■').map(s => s.trim()).filter(Boolean);

  // 섹션별 내용 추출 함수
  function extractBody(block, headerRegex) {
    // 헤더 줄(첫 줄) 제거 후 나머지 본문
    return block
      .replace(headerRegex, '')          // 헤더 라인 제거
      .replace(/^■.*?\n/gm, '')          // 혹시 남아있는 ■ 라인 제거
      .trim();
  }

  for (const block of blocks) {
    // 첫 줄(헤더)만 따로 보기
    const firstLine = block.split('\n')[0]?.trim() || '';

    // 1) 추진배경및목적
    if (/^추진배경\s*및\s*목적/i.test(firstLine) || /^추진배경및목적/i.test(firstLine)) {
      result.추진배경및목적 = extractBody(block, /^추진배경\s*및\s*목적.*?\n|^추진배경및목적.*?\n/);
      continue;
    }

    // 2) 추진내용
    if (/^추진내용/i.test(firstLine) || /추진내용\s*요약/i.test(firstLine)) {
      result.추진내용 = extractBody(block, /^추진내용.*?\n/);
      continue;
    }

    // 3) 기대효과
    if (/^기대효과/i.test(firstLine) || /추진성과\s*또는\s*기대효과/i.test(firstLine)) {
      // [검토결과: ...] 같은 태그가 섞일 수 있어 제거
      const body = extractBody(block, /^기대효과.*?\n|^추진성과\s*또는\s*기대효과.*?\n/);
      result.기대효과 = body.replace(/\[.*?\]/g, '').trim();
      continue;
    }
  }

  // 방어: ■ 없이 한 덩어리로만 왔는데 "추진배경및목적:" 같은 패턴이 있는 경우
  if (!blocks.length) {
    const m1 = raw.match(/추진배경\s*및\s*목적\s*[:：]\s*([\s\S]*?)(?=\n\s*추진내용\s*[:：]|\n\s*기대효과\s*[:：]|$)/i);
    const m2 = raw.match(/추진내용\s*[:：]\s*([\s\S]*?)(?=\n\s*기대효과\s*[:：]|$)/i);
    const m3 = raw.match(/기대효과\s*[:：]\s*([\s\S]*?)$/i);

    if (m1) result.추진배경및목적 = m1[1].trim();
    if (m2) result.추진내용 = m2[1].trim();
    if (m3) result.기대효과 = m3[1].trim();
  }

  return result;
}

return items.map(item => {
  const rewrittenRaw = item.json.output; // AI Agent - 부적합 재작성 결과
  const parsed = parseRewrittenSections(rewrittenRaw);

  const 부적합항목 = item.json.품질검토결과?.부적합항목 || {};

  // 기존(초기 생성/요약) 내용
  let 최종_추진배경및목적 = item.json.AI생성_추진배경및목적;
  let 최종_추진내용 = item.json.AI생성_추진내용;
  let 최종_기대효과 = item.json.AI생성_기대효과;

  // ✅ 부적합으로 판정된 항목만, 재작성 결과가 있을 때만 교체
  if (부적합항목.추진배경및목적 && parsed.추진배경및목적) {
    최종_추진배경및목적 = parsed.추진배경및목적;
    console.log('✅ 추진배경및목적 재작성 반영');
  }

  if (부적합항목.추진내용 && parsed.추진내용) {
    최종_추진내용 = parsed.추진내용;
    console.log('✅ 추진내용 재작성 반영');
  }

  // 기대효과는 보통 "1.\n2.\n3." 형태로 오니 그대로 두되 공백만 정리
  if (부적합항목.기대효과 && parsed.기대효과) {
    최종_기대효과 = parsed.기대효과.trim();
    console.log('✅ 기대효과 재작성 반영');
  }

  return {
    json: {
      ...item.json,
      AI생성_추진배경및목적: 최종_추진배경및목적,
      AI생성_추진내용: 최종_추진내용,
      AI생성_기대효과: 최종_기대효과,
      재작성완료: true,

      // 디버그용(원하면 다음 노드에서 제거 가능)
      __revised_parsed: parsed,
      __revised_raw: pickText(rewrittenRaw),
    },
  };
});

// 재검토 결과 파싱 및 최종 판정
const items = $input.all();

function extractJsonCandidate(text) {
  if (!text) return '';
  let s = String(text).trim();
  s = s.replace(/```[a-zA-Z]*\n([\s\S]*?)```/g, '$1').trim();
  const first = s.indexOf('{');
  const last = s.lastIndexOf('}');
  if (first >= 0 && last > first) return s.slice(first, last + 1);
  return '';
}

function softRepair(t) {
  if (!t) return '';
  let s = String(t).trim();
  s = s.replace(/[""]/g, '"').replace(/['']/g, "'");
  s = s.replace(/,\s*([}\]])/g, '$1');
  return s;
}

return items.map(item => {
  const raw = item.json.output || '';
  const rawText = typeof raw === 'string' ? raw : JSON.stringify(raw);

  console.log('=== Parse Re-review Result ===');

  const cand = extractJsonCandidate(rawText);
  const repaired = softRepair(cand);

  let 재검토결과;
  try {
    재검토결과 = JSON.parse(repaired);
    console.log('재검토 JSON 파싱 성공!');
  } catch (e) {
    console.error('재검토 JSON 파싱 실패:', e.message);
    재검토결과 = {};
  }

  // 기존 품질검토결과 가져오기
  const 기존적합항목 = item.json.품질검토결과?.적합항목 || {};
  const 기존부적합항목 = item.json.품질검토결과?.부적합항목 || {};

  // 최종 적합/부적합 항목 결정
  const 최종적합항목 = { ...기존적합항목 };
  const 최종부적합항목 = {};

  // 재작성된 항목의 재검토 결과 반영
  for (const [항목명, 검토내용] of Object.entries(재검토결과)) {
    if (검토내용.판정 === '적합') {
      // 재작성 후 적합 → 최종 적합 항목에 추가
      최종적합항목[항목명] = 검토내용;
      console.log(`${항목명}: 재작성 후 적합 판정`);
    } else {
      // 재작성 후에도 부적합 → 최종 부적합 항목에 유지
      최종부적합항목[항목명] = 검토내용;
      console.log(`${항목명}: 재작성 후에도 부적합`);
    }
  }

  // 재작성되지 않은 부적합 항목은 그대로 유지
  for (const [항목명, 검토내용] of Object.entries(기존부적합항목)) {
    if (!재검토결과[항목명]) {
      최종부적합항목[항목명] = 검토내용;
    }
  }

  const 적합개수 = Object.keys(최종적합항목).length;
  const 부적합개수 = Object.keys(최종부적합항목).length;
  const 전체판정 = 부적합개수 > 0 ? '일부 부적합' : '모두 적합';

  console.log('재검토 후 적합 항목:', Object.keys(최종적합항목));
  console.log('재검토 후 부적합 항목:', Object.keys(최종부적합항목));
  console.log('최종 판정:', 전체판정);

  return {
    json: {
      ...item.json,
      품질검토결과: {
        적합항목: 최종적합항목,
        부적합항목: 최종부적합항목
