const items         = $input.all();
const expandedItems = $('Expand All Files').all();

console.log(`Structure PDF Data: items=${items.length}, expandedItems=${expandedItems.length}`);

return items.map((item, idx) => {
  const text = item.json.text || '';

  const expandedItem = expandedItems[idx];
  const meta = (expandedItem && expandedItem.json && expandedItem.json._meta)
    ? expandedItem.json._meta
    : {};

  const 실적번호     = meta.실적번호     !== undefined ? meta.실적번호     : '알 수 없음';
  const 실적인덱스   = meta.실적인덱스   !== undefined ? meta.실적인덱스   : -1;
  const 파일명       = meta.파일명       || '알 수 없음';
  const 파일순번     = meta.파일순번     || 1;
  const 실적내파일수 = meta.실적내파일수 || 1;
  const 평가항목     = meta.평가항목     || 'AI 도입활용 사례';
  const 제출시간     = meta.제출시간     || '';

  console.log(`[${idx}] 실적번호: ${실적번호}, 파일명: ${파일명}`);

  function extractMainSections(text) {
    const sections = {};
    const matches  = [...text.matchAll(/□\s*([^\n]+)/g)];
    for (let i = 0; i < matches.length; i++) {
      const title = matches[i][1].trim();
      const start = matches[i].index + matches[i][0].length;
      const end   = i < matches.length - 1 ? matches[i+1].index : text.length;
      sections[title] = text.slice(start, end).trim();
    }
    return sections;
  }

  function parseSubSections(content) {
    const matches = [...content.matchAll(/❍\s*\(\s*([^)]+)\s*\)/g)];
    if (matches.length === 0) return content.replace(/^\s*❍\s*/gm, '').trim();
    const result = {};
    for (let i = 0; i < matches.length; i++) {
      const sub   = matches[i][1].trim();
      const start = matches[i].index + matches[i][0].length;
      const end   = i < matches.length - 1 ? matches[i+1].index : content.length;
      result[sub] = content.slice(start, end)
        .replace(/^\s*-\s*/gm, '').replace(/^\s*❍\s*/gm, '').trim();
    }
    return result;
  }

  const mainSections = extractMainSections(text);

  const structuredData = {
    메타데이터: {
      문서제목:     파일명.replace(/\.pdf$/i, ''),
      원본파일명:   파일명,
      실적번호:     실적번호,
      실적인덱스:   실적인덱스,
      파일순번:     파일순번,
      실적내파일수: 실적내파일수,
      평가항목:     평가항목,
      제출시간:     제출시간
    }
  };

  for (const [sTitle, sContent] of Object.entries(mainSections)) {
    structuredData[sTitle] = parseSubSections(sContent);
  }
  structuredData['원본텍스트'] = text;

  return { json: structuredData };
});

